def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 2:
            base_penalty = ratio ** 4
            penalty = 0
            for k in range(1, 5):
                factor = ((-1) ** k) * ((ratio ** (2 * k + 1)) / (k ** 2 + 1))
                penalty += factor
            priorities[i] = base_penalty + abs(penalty) * 20
            if ratio > 5:
                priorities[i] *= 1.5
            continue
        if 1 < ratio <= 2:
            penalty = 0
            for a in range(1, 6):
                for b in range(1, 4):
                    val = ((-1) ** (a + b)) * (ratio ** (a + b)) / (a * b)
                    penalty += val
            priorities[i] = abs(penalty) * 25
            if ratio > 1.5:
                priorities[i] += (ratio - 1) * 30
            continue
        if 0 < ratio <= 1:
            score = 0
            for j in range(1, 10):
                sign = 1 if j % 3 == 0 else -1
                term = sign * (ratio ** j) / j
                score += term
            multiplier = 20 if ratio < 0.2 else 15 if ratio < 0.5 else 10 if ratio < 0.8 else 5
            priorities[i] = abs(score) * multiplier
            if ratio > 0.85:
                extra = 0
                for m in range(1, 5):
                    extra += (ratio ** (m * 2)) / (m + 2)
                priorities[i] += extra * 3
            continue
        if ratio < 0:
            priorities[i] = np.inf if item != 0 else 0
        else:
            priorities[i] = np.inf
    return priorities
